external_knowledge:
- 'Champion of profitability' refers to the team with the highest profit in a season; 
- 'Profit' is calculated as total revenue minus total expenses; 
- The first season is specified by season_id = 1.

sql:
SELECT SUM(social_media_followers) AS total_social_media_followers
FROM fan_engagement
WHERE season_id = (SELECT season_id FROM seasons WHERE current_season = 1);

SELECT SUM(social_media_followers) AS total_social_media_followers
FROM fan_engagement
WHERE season_id = 2023;
